import org.mockito.kotlin.mock

class UnifiedInboxConfiguratorTest {

    @Before
    fun setUp() {
        // Reset K9.isShowUnifiedInbox before each test
        K9.isShowUnifiedInbox = false
    }

    @Test
    fun `configureUnifiedInbox should not enable unified inbox when there is only one account`() {
        val account1 = createAccount("account1")
        val accountManager = mock<AccountManager> {
            on { getAccounts() } doReturn listOf(account1)
        }
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox should enable unified inbox when there are exactly two accounts`() {
        val account1 = createAccount("account1")
        val account2 = createAccount("account2")
        val accountManager = mock<AccountManager> {
            on { getAccounts() } doReturn listOf(account1, account2)
        }
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox should not change unified inbox setting when there are more than two accounts`() {
        val account1 = createAccount("account1")
        val account2 = createAccount("account2")
        val account3 = createAccount("account3")
        val accountManager = mock<AccountManager> {
            on { getAccounts() } doReturn listOf(account1, account2, account3)
        }
        val configurator = UnifiedInboxConfigurator(accountManager)

        // Start with unified inbox disabled
        K9.isShowUnifiedInbox = false

        configurator.configureUnifiedInbox()

        // Should remain disabled for 3 accounts
        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox should preserve user setting when adding third account with unified inbox enabled`() {
        val account1 = createAccount("account1")
        val account2 = createAccount("account2")
        val account3 = createAccount("account3")
        val accountManager = mock<AccountManager> {
            on { getAccounts() } doReturn listOf(account1, account2, account3)
        }
        val configurator = UnifiedInboxConfigurator(accountManager)

        // Start with unified inbox enabled (user preference)
        K9.isShowUnifiedInbox = true

        configurator.configureUnifiedInbox()

        // Should remain enabled for 3 accounts (respecting user preference)
        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox should not enable unified inbox for zero accounts`() {
        val accountManager = mock<AccountManager> {
            on { getAccounts() } doReturn emptyList()
        }
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    private fun createAccount(uuid: String): Account {
        return Account(uuid)
    }
}
